parameters.query:
query GetCardsByField(
  $fieldId: String!,
  $fieldValue: String!,
  $first: Int = 50
) {
  findCards(
    pipeId: 306498227
    first: $first
    search: { fieldId: $fieldId, fieldValue: $fieldValue }
  ) {
    edges {
      node {
        id
        title
        fields {
          field { id label type }
          value
          report_value
          array_value
        }
      }
    }
  }
}

=mutation ($cardId: ID!, $toAdd: [UndefinedInput!]!) {
  updateFieldsValues(
    input: {
      nodeId: $cardId
      values: [
        {
          fieldId: "cards_de_contatos"
          value: $toAdd
          operation: ADD
        }
      ]
    }
  ) {
    success
    userErrors { field message }
    updatedNode {
      ... on Card { id }
    }
  }
}

